def hedef_toplam_var_mi(sayilar, hedef):
    sol = 0
    toplam = 0
    for sag in range(len(sayilar)):
        toplam += sayilar[sag]
        while toplam > hedef and sol <= sag:
            toplam -= sayilar[sol]
            sol += 1
        if toplam == hedef and sol <= sag:
            return True
    return False
